+    /// The end thumb controls the upper value.
+    End,
+}
+
+impl ThumbIndex {
+    fn index(self) -> usize {
+        match self {
+            Self::Start => 0,
+            Self::End => 1,
+        }
+    }
+
+    fn other(self) -> Self {
+        match self {
+            Self::Start => Self::End,
+            Self::End => Self::Start,
+        }
+    }
