    pub readonly: bool,

    /// Whether the range slider is invalid.
    pub invalid: bool,

    /// Range-slider layout orientation.
    pub orientation: Orientation,

    /// Text direction used for horizontal keyboard and visual mirroring.
    pub dir: Direction,

