  1481	    ctx: &Context,
  1482	    thumb: ThumbIndex,
  1483	    raw: f64,
  1484	    track_drag: bool,
  1485	) -> (ThumbIndex, [f64; 2]) {
  1486	    let mut active = thumb;
  1487	    let (min, max) = normalized_bounds(ctx.min, ctx.max);
  1488	    let gap = effective_gap(ctx);
