/// Identifies one of the two range-slider thumbs.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum ThumbIndex {
    /// The start thumb controls the lower value.
    Start,

    /// The end thumb controls the upper value.
    End,
}

impl ThumbIndex {
    fn index(self) -> usize {
        match self {
            Self::Start => 0,
            Self::End => 1,
        }
    }

    fn other(self) -> Self {
        match self {
            Self::Start => Self::End,
            Self::End => Self::Start,
        }
    }

    fn token(self) -> &'static str {
        match self {
            Self::Start => "0",
            Self::End => "1",
        }
    }
}

/// The state of the `RangeSlider` component.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum State {
    /// The component is idle.
    Idle,

    /// One thumb is focused.
    Focused {
        /// The focused thumb.
        thumb: ThumbIndex,
    },

    /// One thumb is being dragged.
    Dragging {
        /// The dragged thumb.
        thumb: ThumbIndex,
    },
}

impl Display for State {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.write_str(match self {
            Self::Idle => "idle",
            Self::Focused { .. } => "focused",
            Self::Dragging { .. } => "dragging",
        })
    }
}

