    fn value_from_pointer_uses_adapter_supplied_geometry() {
        let svc = service(props());
        let track = Rect {
            x: 10.0,
            y: 20.0,
            width: 200.0,
            height: 100.0,
        };

        assert_eq!(
            value_from_pointer(SliderPointer { x: 110.0, y: 70.0 }, track, svc.context()),
            Some(50.0)
        );
        assert_eq!(
            value_from_pointer(SliderPointer { x: 210.0, y: 70.0 }, track, svc.context()),
            Some(100.0)
        );
        let offset_bounds = service(Props {
            min: 10.0,
            max: 110.0,
            ..props()
        });
        assert_eq!(
            value_from_pointer(
                SliderPointer { x: 110.0, y: 70.0 },
                track,
                offset_bounds.context()
            ),
            Some(60.0)
        );

        let rtl = service(Props {
            dir: Direction::Rtl,
            ..props()
        });

        assert_eq!(
            value_from_pointer(SliderPointer { x: 60.0, y: 70.0 }, track, rtl.context()),
            Some(75.0)
        );

        let vertical = service(Props {
            orientation: Orientation::Vertical,
            ..props()
        });

        assert_eq!(
            value_from_pointer(
                SliderPointer { x: 110.0, y: 45.0 },
                track,
                vertical.context()
            ),
            Some(75.0)
        );

        assert_eq!(
            value_from_pointer(
                SliderPointer {
                    x: f64::NAN,
                    y: 45.0
                },
                track,
                svc.context()
            ),
            None
        );
        assert_eq!(
            value_from_pointer(
                SliderPointer { x: 10.0, y: 10.0 },
                Rect {
                    width: 0.0,
                    ..track
                },
                svc.context()
            ),
            None
        );

        assert_eq!(
            value_from_pointer(
                SliderPointer { x: 10.0, y: 10.0 },
                Rect {
                    x: f64::NAN,
                    ..track
                },
                svc.context()
            ),
            None
        );
        assert_eq!(
            value_from_pointer(
                SliderPointer { x: 10.0, y: 10.0 },
                Rect {
                    width: f64::NAN,
                    ..track
                },
                svc.context()
            ),
            None
        );
        assert_eq!(
            value_from_pointer(
                SliderPointer {
                    x: 110.0,
                    y: f64::NAN,
                },
                track,
                vertical.context()
            ),
            None
        );
        assert_eq!(
            value_from_pointer(
                SliderPointer { x: 10.0, y: 10.0 },
                Rect {
                    y: f64::NAN,
                    ..track
                },
