   558	fn snap_to_step(value: f64, min: f64, max: f64, step: f64) -> f64 {
   559	    let clamped = value.clamp(min, max);
   560	    let steps_from_min = ((clamped - min) / step).round();
   561	    (min + steps_from_min * step).clamp(min, max)
   562	}
