+```rust
+/// Machine for the RangeSlider component.
+#[derive(Debug)]
+pub struct Machine;
+
+/// Typed identifier for side effects emitted by the range-slider machine.
+#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
